<?php
namespace App\Console\Commands; use App\Models\{KnowledgeMachine,KnowledgeServiceCode}; use Illuminate\Console\Command; use Illuminate\Support\Facades\App;
class ImportKnowledgeServiceCodes extends Command { protected $signature='knowledge:import-service-codes {path : Absolute local PDF path} {--machine=13003093} {--production-confirm}'; protected $description='Import encrypted service codes from a private local PDF without displaying them'; public function handle():int { if(App::isProduction()&&!$this->option('production-confirm')){$this->error('Refusing production import without --production-confirm.');return self::FAILURE;}$path=realpath($this->argument('path'));if(!$path||!is_file($path)||strtolower(pathinfo($path,PATHINFO_EXTENSION))!=='pdf'){$this->error('A readable PDF path is required.');return self::FAILURE;}$machine=KnowledgeMachine::where('product_code',$this->option('machine'))->firstOrFail();$command='pdftotext -layout '.escapeshellarg($path).' -';exec($command,$lines,$status);if($status!==0){$this->error('PDF extraction failed.');return self::FAILURE;}$count=0;foreach($lines as $line){if(!preg_match('/^\s*(.{3,80}?)\s{2,}(.{0,160}?)\s{2,}([A-Za-z0-9*#._-]{2,40})\s*$/u',$line,$m))continue;$function=trim($m[1]);$description=trim($m[2])?:null;$code=trim($m[3]);if($function===''||preg_match('/password|service code/i',$function))continue;KnowledgeServiceCode::updateOrCreate(['knowledge_machine_id'=>$machine->id,'function_name'=>$function],['description'=>$description,'service_code'=>$code]);$count++;}$this->info("Imported {$count} encrypted service-code records.");return self::SUCCESS;} }
